{"subject":"Geography","year":2001,"question":"The total number of people living in a given area at a given time is the:","options":[\"Population size\",\"Population density\",\"Population distribution\",\"Population composition\"],"correctIndex":0,"explanation":"Population size is the total count."},
{"subject":"Geography","year":2002,"question":"The average number of people per unit area is:","options":[\"Population density\",\"Population size\",\"Population distribution\",\"Population growth\"],"correctIndex":0,"explanation":"Density = population / area."},
{"subject":"Geography","year":2003,"question":"The natural increase of a population is:","options":[\"Birth rate - Death rate\",\"Birth rate + Death rate\",\"Death rate - Birth rate\",\"Birth rate / Death rate\"],"correctIndex":0,"explanation":"Natural increase = Crude Birth Rate - Crude Death Rate."},
{"subject":"Geography","year":2004,"question":"The demographic transition model has:","options":[\"4 stages\",\"3 stages\",\"5 stages\",\"2 stages\"],"correctIndex":0,"explanation":"The classic model has 4 stages."},
{"subject":"Geography","year":2005,"question":"In the first stage of demographic transition, birth and death rates are:","options":[\"High and fluctuating\",\"Low\",\"Declining\",\"Stable\"],"correctIndex":0,"explanation":"Stage 1 has high birth and death rates."},
{"subject":"Geography","year":2006,"question":"In the third stage of demographic transition, the population:","options":[\"Grows slowly\",\"Grows rapidly\",\"Stabilises\",\"Declines\"],"correctIndex":0,"explanation":"Stage 3 has declining birth rates and low death rates, growth slows."},
{"subject":"Geography","year":2007,"question":"The fourth stage of demographic transition has:","options":[\"Low birth and death rates\",\"High birth and death rates\",\"High birth and low death\",\"Low birth and high death\"],"correctIndex":0,"explanation":"Stage 4 is the post‑industrial stage."},
{"subject":"Geography","year":2008,"question":"A population pyramid with a broad base indicates:","options":[\"High birth rate\",\"Low birth rate\",\"Aging population\",\"Declining population\"],"correctIndex":0,"explanation":"A wide base means many young people (high fertility)."},
{"subject":"Geography","year":2009,"question":"A population pyramid with a narrow base suggests:","options":[\"Low birth rate\",\"High birth rate\",\"High death rate\",\"Rapid growth\"],"correctIndex":0,"explanation":"Narrow base indicates declining fertility."},
{"subject":"Geography","year":2010,"question":"Push factors in migration include:","options":[\"Unemployment, poverty, war\",\"Better job opportunities, higher pay\",\"Better education, healthcare\",\"Family reunification\"],"correctIndex":0,"explanation":"Push factors drive people away from their origin."},
{"subject":"Geography","year":2011,"question":"Pull factors in migration include:","options":[\"Better job opportunities, higher pay\",\"Unemployment, poverty, war\",\"Famine, drought\",\"Political unrest\"],"correctIndex":0,"explanation":"Pull factors attract people to a destination."},
{"subject":"Geography","year":2012,"question":"Rural‑urban migration is a common phenomenon in:","options":[\"Developing countries\",\"Developed countries\",\"All countries\",\"None\"],"correctIndex":0,"explanation":"Rural‑urban migration is prevalent in developing nations."},
{"subject":"Geography","year":2013,"question":"A consequence of rural‑urban migration is:","options":[\"Urban overcrowding and rural depopulation\",\"Rural growth\",\"Urban decline\",\"Balanced development\"],"correctIndex":0,"explanation":"It leads to urban slums and ageing rural populations."},
{"subject":"Geography","year":2014,"question":"The push factor for rural‑urban migration often includes:","options":[\"Lack of employment and services in rural areas\",\"Better wages in cities\",\"Better education in cities\",\"Improved healthcare\"],"correctIndex":0,"explanation":"Rural areas often lack jobs and amenities."},
{"subject":"Geography","year":2015,"question":"The main agricultural activity in Nigeria\\"s savanna region is:","options":[\"Subsistence farming with millet, sorghum, and cattle rearing\",\"Palm oil production\",\"Cocoa farming\",\"Rubber production\"],"correctIndex":0,"explanation":"The savanna is suitable for grains and livestock."},
