{"subject":"Geography","year":2001,"question":"The main source of nitrous oxide emissions is:","options":[\"Agricultural soils and fertilizers\",\"Cars and factories\",\"Waste treatment\",\"Natural processes\"],"correctIndex":0,"explanation":"Agricultural nitrogen use is the main source."},
{"subject":"Geography","year":2002,"question":"The term \"climate change\" refers to:","options":[\"Long‑term changes in temperature and weather patterns\",\"Short‑term weather variations\",\"Seasonal changes\",\"Daily changes\"],"correctIndex":0,"explanation":"Climate change is long‑term."},
{"subject":"Geography","year":2003,"question":"The effects of climate change include:","options":[\"Sea level rise, melting glaciers, extreme weather\",\"Cooling of the planet\",\"Less rainfall everywhere\",\"No effects\"],"correctIndex":0,"explanation":"These are well‑documented effects."},
{"subject":"Geography","year":2004,"question":"The main international agreement on biodiversity is the:","options":[\"Convention on Biological Diversity (CBD)\",\"Kyoto Protocol\",\"Paris Agreement\",\"Montreal Protocol\"],"correctIndex":0,"explanation":"The CBD is the key biodiversity treaty."},
{"subject":"Geography","year":2005,"question":"The Montreal Protocol is aimed at:","options":[\"Protecting the ozone layer\",\"Reducing CO₂ emissions\",\"Protecting biodiversity\",\"Reducing ocean pollution\"],"correctIndex":0,"explanation":"Montreal was for ozone depletion."},
{"subject":"Geography","year":2006,"question":"The Kyoto Protocol was:","options":[\"A legally binding treaty to reduce greenhouse gas emissions\",\"A voluntary agreement\",\"A trade deal\",\"A biodiversity treaty\"],"correctIndex":0,"explanation":"Kyoto set binding emission targets."},
{"subject":"Geography","year":2007,"question":"The Doha Amendment to the Kyoto Protocol extended:","options":[\"The second commitment period (2013‑2020)\",\"The first commitment period\",\"The Paris Agreement\",\"The Montreal Protocol\"],"correctIndex":0,"explanation":"Doha was for the second commitment period."},
{"subject":"Geography","year":2008,"question":"The UN Framework Convention on Climate Change (UNFCCC) was adopted in:","options":[\"1992\",\"1997\",\"2001\",\"2007\"],"correctIndex":0,"explanation":"UNFCCC was adopted in 1992."},
